import { useState } from 'react';
import './App.css';
import Admin from './pages/Admin';
import Login from './pages/Login';
import Orders from './pages/Orders';
import { kakaoPayReady } from './pages/KakaoPay';

const initialProducts = [
  { id: 1, name: '신선 사과', price: 5000, category: '식품', image: null },
  { id: 2, name: '제주 감귤', price: 8000, category: '식품', image: null },
  { id: 3, name: '세탁 세제', price: 12000, category: '생활용품', image: null },
  { id: 4, name: '콜라 1.5L', price: 3000, category: '음료', image: null },
  { id: 5, name: '냉동 만두', price: 7000, category: '냉동식품', image: null },
  { id: 6, name: '포카칩', price: 2500, category: '과자/간식', image: null },
];

const COLORS = {
  primary: '#2e7d32',
  primaryLight: '#4caf50',
  primaryDark: '#1b5e20',
  accent: '#ff6f00',
  bg: '#f9fbe7',
  card: '#ffffff',
  text: '#1a1a1a',
  textMuted: '#666',
  border: '#e0e0e0',
  danger: '#e53935',
};

function App() {
  const [page, setPage] = useState('login');
  const [products, setProducts] = useState(initialProducts);
  const [cart, setCart] = useState([]);
  const [user, setUser] = useState(null);
  const [orders, setOrders] = useState([]);

  const handleLogin = (loggedInUser) => {
    setUser(loggedInUser);
    setPage('home');
  };

  const handleLogout = () => {
    setUser(null);
    setCart([]);
    setPage('login');
  };

  const addToCart = (product) => {
    const existing = cart.find((item) => item.id === product.id);
    if (existing) {
      setCart(cart.map((item) =>
        item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
      ));
    } else {
      setCart([...cart, { ...product, quantity: 1 }]);
    }
    alert(`${product.name}이(가) 장바구니에 담겼어요! 🛒`);
  };

  const removeFromCart = (id) => {
    setCart(cart.filter((item) => item.id !== id));
  };

  const updateQuantity = (id, delta) => {
    setCart(cart.map((item) =>
      item.id === id
        ? { ...item, quantity: Math.max(1, item.quantity + delta) }
        : item
    ));
  };

  const totalPrice = cart.reduce((sum, item) => sum + item.price * item.quantity, 0);

  const handlePayment = async () => {
    if (cart.length === 0) {
      alert('장바구니가 비어있어요!');
      return;
    }
    try {
      const orderInfo = {
        orderId: `order_${Date.now()}`,
        userId: user.email,
        itemName: cart.length === 1 ? cart[0].name : `${cart[0].name} 외 ${cart.length - 1}건`,
        quantity: cart.reduce((sum, item) => sum + item.quantity, 0),
        totalAmount: totalPrice,
      };
      const result = await kakaoPayReady(orderInfo);
      if (result.next_redirect_pc_url) {
        const newOrder = {
          id: orderInfo.orderId,
          date: new Date().toLocaleString('ko-KR'),
          items: [...cart],
          totalPrice,
        };
        setOrders([newOrder, ...orders]);
        setCart([]);
        window.open(result.next_redirect_pc_url, '_blank');
      }
    } catch (error) {
      alert('결제 준비 중 오류가 발생했어요. 잠시 후 다시 시도해주세요.');
    }
  };

  if (page === 'login') {
    return (
      <div style={{ minHeight: '100vh', background: COLORS.bg }}>
        <header style={{ background: COLORS.primary, padding: '16px 32px', boxShadow: '0 2px 8px rgba(0,0,0,0.15)' }}>
          <h1 style={{ color: 'white', margin: 0, fontSize: '26px', letterSpacing: '1px' }}>🛒 SR Mart</h1>
        </header>
        <Login onLogin={handleLogin} />
        <footer style={{ background: COLORS.primaryDark, color: 'white', padding: '24px', textAlign: 'center', marginTop: '40px' }}>
          <p style={{ margin: 0, fontSize: '14px' }}>© 2026 SR Mart. All rights reserved.</p>
        </footer>
      </div>
    );
  }

  return (
    <div style={{ minHeight: '100vh', background: COLORS.bg }}>
      {/* 헤더 */}
      <header style={{ background: COLORS.primary, padding: '0 32px', boxShadow: '0 2px 8px rgba(0,0,0,0.15)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', height: '64px' }}>
        <h1 style={{ color: 'white', margin: 0, fontSize: '24px', cursor: 'pointer', letterSpacing: '1px' }} onClick={() => setPage('home')}>🛒 SR Mart</h1>
        <nav style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
          {[
            { label: '홈', key: 'home' },
            { label: '주문내역', key: 'orders' },
          ].map((item) => (
            <button
              key={item.key}
              onClick={() => setPage(item.key)}
              style={{ background: page === item.key ? 'rgba(255,255,255,0.25)' : 'transparent', color: 'white', border: 'none', borderRadius: '8px', padding: '8px 16px', cursor: 'pointer', fontSize: '14px', fontWeight: page === item.key ? 'bold' : 'normal' }}
            >
              {item.label}
            </button>
          ))}
          <button
            onClick={() => setPage('cart')}
            style={{ background: page === 'cart' ? 'rgba(255,255,255,0.25)' : 'transparent', color: 'white', border: 'none', borderRadius: '8px', padding: '8px 16px', cursor: 'pointer', fontSize: '14px', position: 'relative' }}
          >
            🛒 장바구니
            {cart.length > 0 && (
              <span style={{ position: 'absolute', top: '2px', right: '2px', background: COLORS.accent, borderRadius: '50%', width: '18px', height: '18px', fontSize: '11px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold' }}>
                {cart.length}
              </span>
            )}
          </button>
          {user && user.email === 'admin@srmart.com' && (
            <button
              onClick={() => setPage('admin')}
              style={{ background: page === 'admin' ? 'rgba(255,255,255,0.25)' : 'transparent', color: '#ffd54f', border: '1px solid #ffd54f', borderRadius: '8px', padding: '8px 16px', cursor: 'pointer', fontSize: '14px', fontWeight: 'bold' }}
            >
              ⚙️ 관리자
            </button>
          )}
          <div style={{ borderLeft: '1px solid rgba(255,255,255,0.3)', paddingLeft: '12px', marginLeft: '4px', display: 'flex', alignItems: 'center', gap: '8px' }}>
            <span style={{ color: 'white', fontSize: '13px' }}>👤 {user && user.name}님</span>
            <button onClick={handleLogout} style={{ background: 'transparent', color: '#ffcdd2', border: '1px solid rgba(255,255,255,0.3)', borderRadius: '8px', padding: '6px 12px', cursor: 'pointer', fontSize: '13px' }}>
              로그아웃
            </button>
          </div>
        </nav>
      </header>

      {/* 홈 */}
      {page === 'home' && (
        <main style={{ padding: '32px', maxWidth: '1200px', margin: '0 auto' }}>
          {/* 배너 */}
          <div style={{ background: `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.primaryLight})`, borderRadius: '16px', padding: '40px 48px', marginBottom: '32px', color: 'white' }}>
            <h2 style={{ margin: '0 0 8px', fontSize: '28px' }}>🛒 SR Mart에 오신 것을 환영해요!</h2>
            <p style={{ margin: 0, opacity: 0.9, fontSize: '16px' }}>신선하고 다양한 상품을 만나보세요</p>
          </div>

          <h2 style={{ marginBottom: '20px', color: COLORS.primaryDark, fontSize: '20px' }}>추천 상품</h2>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '20px' }}>
            {products.map((product) => (
              <div key={product.id} style={{ background: COLORS.card, border: `1px solid ${COLORS.border}`, borderRadius: '12px', overflow: 'hidden', boxShadow: '0 2px 8px rgba(0,0,0,0.06)', transition: 'transform 0.2s' }}>
                {product.image ? (
                  <img src={product.image} alt={product.name} style={{ width: '100%', height: '180px', objectFit: 'contain', background: '#f5f5f5' }} />
                ) : (
                  <div style={{ background: '#f1f8e9', height: '180px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '48px' }}>🛍️</div>
                )}
                <div style={{ padding: '16px' }}>
                  <span style={{ fontSize: '11px', background: '#e8f5e9', color: COLORS.primary, padding: '3px 8px', borderRadius: '20px', fontWeight: 'bold' }}>{product.category}</span>
                  <h3 style={{ margin: '10px 0 6px', fontSize: '16px', color: COLORS.text }}>{product.name}</h3>
                  <p style={{ color: COLORS.primary, fontWeight: 'bold', margin: '0 0 14px', fontSize: '18px' }}>₩{product.price.toLocaleString()}</p>
                  <button
                    onClick={() => addToCart(product)}
                    style={{ background: COLORS.primary, color: 'white', border: 'none', borderRadius: '8px', padding: '10px 16px', cursor: 'pointer', width: '100%', fontSize: '14px', fontWeight: 'bold' }}>
                    🛒 장바구니 담기
                  </button>
                </div>
              </div>
            ))}
          </div>
        </main>
      )}

      {/* 장바구니 */}
      {page === 'cart' && (
        <main style={{ padding: '32px', maxWidth: '800px', margin: '0 auto' }}>
          <h2 style={{ marginBottom: '24px', color: COLORS.primaryDark }}>🛒 장바구니</h2>
          {cart.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '80px', color: COLORS.textMuted, background: COLORS.card, borderRadius: '16px', border: `1px solid ${COLORS.border}` }}>
              <p style={{ fontSize: '56px', margin: '0 0 16px' }}>🛒</p>
              <p style={{ fontSize: '16px', margin: '0 0 24px' }}>장바구니가 비어있어요!</p>
              <button onClick={() => setPage('home')} style={{ padding: '12px 28px', background: COLORS.primary, color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontSize: '15px', fontWeight: 'bold' }}>
                쇼핑 계속하기
              </button>
            </div>
          ) : (
            <div>
              <div style={{ background: COLORS.card, borderRadius: '12px', border: `1px solid ${COLORS.border}`, overflow: 'hidden', marginBottom: '16px' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                  <thead>
                    <tr style={{ background: COLORS.primary, color: 'white' }}>
                      <th style={{ padding: '14px 16px', textAlign: 'left' }}>이미지</th>
                      <th style={{ padding: '14px 16px', textAlign: 'left' }}>상품명</th>
                      <th style={{ padding: '14px 16px', textAlign: 'center' }}>수량</th>
                      <th style={{ padding: '14px 16px', textAlign: 'right' }}>금액</th>
                      <th style={{ padding: '14px 16px', textAlign: 'center' }}>삭제</th>
                    </tr>
                  </thead>
                  <tbody>
                    {cart.map((item) => (
                      <tr key={item.id} style={{ borderBottom: `1px solid ${COLORS.border}` }}>
                        <td style={{ padding: '14px 16px' }}>
                          {item.image ? (
                            <img src={item.image} alt={item.name} style={{ width: '52px', height: '52px', objectFit: 'contain', background: '#f5f5f5', borderRadius: '8px' }} />
                          ) : (
                            <div style={{ width: '52px', height: '52px', background: '#f1f8e9', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '20px' }}>🛍️</div>
                          )}
                        </td>
                        <td style={{ padding: '14px 16px', fontWeight: '500' }}>{item.name}</td>
                        <td style={{ padding: '14px 16px', textAlign: 'center' }}>
                          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                            <button onClick={() => updateQuantity(item.id, -1)} style={{ width: '30px', height: '30px', background: '#f1f8e9', border: `1px solid ${COLORS.border}`, borderRadius: '6px', cursor: 'pointer', fontSize: '16px', color: COLORS.primary, fontWeight: 'bold' }}>-</button>
                            <span style={{ minWidth: '28px', textAlign: 'center', fontWeight: 'bold' }}>{item.quantity}</span>
                            <button onClick={() => updateQuantity(item.id, 1)} style={{ width: '30px', height: '30px', background: '#f1f8e9', border: `1px solid ${COLORS.border}`, borderRadius: '6px', cursor: 'pointer', fontSize: '16px', color: COLORS.primary, fontWeight: 'bold' }}>+</button>
                          </div>
                        </td>
                        <td style={{ padding: '14px 16px', textAlign: 'right', color: COLORS.primary, fontWeight: 'bold', fontSize: '16px' }}>₩{(item.price * item.quantity).toLocaleString()}</td>
                        <td style={{ padding: '14px 16px', textAlign: 'center' }}>
                          <button onClick={() => removeFromCart(item.id)} style={{ background: COLORS.danger, color: 'white', border: 'none', borderRadius: '6px', padding: '7px 14px', cursor: 'pointer', fontSize: '13px' }}>삭제</button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
              <div style={{ background: COLORS.card, borderRadius: '12px', border: `1px solid ${COLORS.border}`, padding: '20px 24px', textAlign: 'right' }}>
                <p style={{ fontSize: '22px', fontWeight: 'bold', margin: '0 0 16px', color: COLORS.primaryDark }}>총 합계: ₩{totalPrice.toLocaleString()}</p>
                <button onClick={handlePayment} style={{ padding: '14px 36px', background: '#FFCD00', color: '#1a1a1a', border: 'none', borderRadius: '10px', fontSize: '16px', cursor: 'pointer', fontWeight: 'bold', boxShadow: '0 2px 8px rgba(255,205,0,0.4)' }}>
                  카카오페이로 결제하기
                </button>
              </div>
            </div>
          )}
        </main>
      )}

      {page === 'orders' && <Orders orders={orders} />}

      {page === 'admin' && (
        <Admin products={products} setProducts={setProducts} />
      )}

      {/* 푸터 */}
      <footer style={{ background: COLORS.primaryDark, color: 'white', padding: '32px', textAlign: 'center', marginTop: '60px' }}>
        <p style={{ margin: '0 0 8px', fontSize: '18px', fontWeight: 'bold' }}>🛒 SR Mart</p>
        <p style={{ margin: 0, fontSize: '13px', opacity: 0.7 }}>© 2026 SR Mart. All rights reserved.</p>
      </footer>
    </div>
  );
}

export default App;
